    Build = apps.get_model("builds", "Build")
    for slug, short, full in DESCRIPTIONS:
        b = Build.objects.filter(slug=slug).first()
        if b is None:
            continue
        changed = False
        # Идемпотентно: не перетираем то, что уже заполнено вручную.
        if not (b.short_description or "").strip():
            b.short_description = short
            changed = True
        if not (b.description or "").strip():
            b.description = full
            changed = True
        if changed:
            b.save(update_fields=["short_description", "description", "updated_at"])


